class User:
    def __init__(self, name):
        self.name = name
    def __repr__(self):
        return f"User({self.name})"

class Admin(User):
    def __init__(self, name, level):
        super().__init__(name)
        self.level = level

class User:
    @classmethod
    def guest(cls):
        return cls("guest")

class Circle:
    def __init__(self, r):
        self.r = r
    @property
    def area(self):
        return 3.14 * self.r ** 2

class Money:
    def __init__(self, cents):
        self.cents = cents
    def __eq__(self, other):
        return self.cents == other.cents

