class Bag:
    def __init__(self, items):
        self.items = items
    def __len__(self):
        return len(self.items)

class Math:
    @staticmethod
    def add(a, b):
        return a + b

def count_up(n):
    for i in range(n):
        yield i

def flatten(rows):
    for row in rows:
        yield from row

def loud(fn):
    def wrapper(*args):
        return fn(*args)
    return wrapper

@lru_cache
def fib(n):
    return n if n < 2 else fib(n - 1) + fib(n - 2)

def timed(fn):
    @wraps(fn)
    def inner(*args, **kwargs):
        return fn(*args, **kwargs)
    return inner

